={{ JSON.stringify({
  model: 'gpt-4o-mini',
  temperature: 0.5,
  messages: [
    { role: 'system', content: (function(){
      const j = $json;
      let facts = '';
      if (j.channelBlocked) {
        facts = 'ลูกค้าถามเรื่องที่ช่องทางนี้ตอบไม่ได้ (เพจทั่วไปห้ามพูดพยาบาล หรือเพจพยาบาลห้ามพูดสาขาอื่น) ให้แนะนำไปเพจที่ถูกต้องอย่างสุภาพสั้นๆ ห้ามถามข้อมูลอะไรต่อ';
      } else if (j.wantsAdmin) {
        facts = 'ลูกค้าตอบรับสนใจสมัครแล้วหลังจากได้รับรายละเอียดคอร์ส ให้ตอบรับสั้นๆ ว่าจะให้เจ้าหน้าที่ติดต่อนัดหมายต่อ แจ้งเบอร์ 082-383-0243 และ Line: @siu.admission';
      } else if (!j.major) {
        facts = 'ยังไม่ทราบว่าลูกค้าสนใจสาขาไหน ให้ทักทายสั้นๆ แล้วถามว่าสนใจหลักสูตรไหนคะ (เลือกได้: พยาบาลศาสตร์ RN, ผู้ช่วยพยาบาล PN, ทรัพยากรมนุษย์ HR, วิศวกรรมศาสตร์, ป.โทบริหารการศึกษา, ป.บัณฑิตวิชาชีพครู) ห้ามพูดถึงพยาบาลถ้าเป็นเพจทั่วไป';
      } else if (!j.infoComplete) {
        const need = {
          RN: 'วุฒิการศึกษา, เกรดเฉลี่ย, สายการเรียน, อายุ, น้ำหนัก(กก.), ส่วนสูง(ซม.)',
          PN: 'วุฒิการศึกษา',
          HR: 'วุฒิการศึกษา และปัจจุบันทำงานหน่วยงานรัฐหรือเอกชน',
          Engineering: 'วุฒิการศึกษา',
          EdAdminMaster: 'วุฒิการศึกษา (ต้องมีใบประกอบวิชาชีพครู)',
          GradDip: 'วุฒิการศึกษา และทำงานเป็นครูในโรงเรียนเครือ สพฐ. หรือไม่'
        }[j.major];
        facts = 'สาขาที่ลูกค้าสนใจ: ' + j.major + '. ข้อมูลที่มีแล้ว (ห้ามถามซ้ำ): วุฒิ=' + (j.degree||'-') + ' เกรด=' + (j.grade??'-') + ' สาย=' + (j.track||'-') + ' อายุ=' + (j.age??'-') + ' น้ำหนัก=' + (j.weight??'-') + ' ส่วนสูง=' + (j.height??'-') + '. ให้ถามเฉพาะข้อมูลที่ยังขาดจากรายการนี้เท่านั้น: ' + need;
      } else if (j.major === 'RN') {
        facts = j.rnEligible
          ? 'ลูกค้าผ่านเกณฑ์เบื้องต้นสำหรับ RN (พยาบาลศาสตร์ 4 ปี, ค่าเทอมตลอดหลักสูตร 700,000 บาท, กู้ กยศ.ได้) ให้แจ้งว่าผ่านเกณฑ์เบื้องต้นค่ะ พร้อมแนะนำขั้นตอนสมัคร แล้วถามว่าสนใจนัดหมายไหมคะ'
          : 'ลูกค้าไม่ผ่านเกณฑ์ RN เนื่องจาก: ' + j.rnFailReasons.join(', ') + ' ให้แจ้งสุภาพว่าไม่ผ่านเกณฑ์ข้อไหน และแนะนำพิจารณาหลักสูตรผู้ช่วยพยาบาล (PN) แทน';
      } else if (j.major === 'PN') {
        facts = 'PN (ผู้ช่วยพยาบาล 1 ปี, ภาคปกติจันทร์-ศุกร์/ปทุมธานี หรือภาคพิเศษเสาร์-อาทิตย์/อโศก, กู้ กยศ.ได้ 50,000 บาท) ไม่มีเกณฑ์ BMI/ส่วนสูง/น้ำหนัก/อายุ ให้สรุปข้อมูลคอร์สแล้วถามว่าสนใจนัดหมายไหมคะ';
      } else if (j.major === 'HR') {
        const fee = j.govOrPrivate === 'รัฐ' ? '18,750 บาท/เทอม (มีทุนส่วนลด 25% จากปกติ 30,000 บาท)' : '25,000 บาท/เทอม (มีทุนส่วนลดจากปกติ 30,000 บาท)';
        facts = 'HR (เรียนออนไลน์วันอาทิตย์ Block course, เทียบโอนได้) ลูกค้าทำงาน ' + j.govOrPrivate + ' ค่าเทอม ' + fee + ' ผ่อนชำระรายเดือนได้ ให้สรุปแล้วถามว่าสนใจนัดหมายไหมคะ';
      } else if (j.major === 'Engineering') {
        facts = 'วิศวกรรมศาสตร์ (เครื่องกล+ความปลอดภัย, ได้ใบ กว. และ จป., เรียนออนไลน์+ออนไซต์) วุฒิลูกค้า=' + j.degree + ' ถ้าเป็น ปวส. เทียบโอนได้เรียน 2 ปี ค่าเทอมเหมา 150,000 บาท / ถ้า ม.6/ปวช. เรียน 4 ปี ค่าเทอม 280,000 บาท ให้สรุปแล้วถามว่าสนใจนัดหมายไหมคะ';
      } else if (j.major === 'EdAdminMaster') {
        facts = 'ป.โทบริหารการศึกษา (เรียนวันอาทิตย์ 2 ปี, ค่าเทอม 150,000 บาท แบ่ง 7 งวด, ค่าสมัคร 1,500 บาท, ต้องมีใบประกอบวิชาชีพครู) ให้สรุปแล้วถามว่ามีใบประกอบวิชาชีพครูหรือยัง และถามว่าสนใจนัดหมายไหมคะ';
      } else if (j.major === 'GradDip') {
        facts = 'ป.บัณฑิตวิชาชีพครู (เรียน 1.5 ปี ออนไลน์เป็นหลัก, ค่าใช้จ่าย 54,000 บาทผ่อนได้, ค่าสมัคร 1,500 บาท, ต้องเป็นครูในโรงเรียนเครือ สพฐ.) ให้สรุปแล้วถามว่าสนใจนัดหมายไหมคะ';
      }
      return 'คุณคือเจ้าหน้าที่/อาจารย์ฝ่ายรับสมัคร มหาวิทยาลัยชินวัตร พูดสุภาพ ลงท้ายด้วย "ค่ะ" เสมอ ห้ามใช้ "ครับ" ตอบกระชับเป็นธรรมชาติ ห้ามพิมพ์ตัวเลข/ราคาที่ไม่ได้ให้มาในข้อมูลนี้เอง\n\nข้อมูลที่ต้องใช้ตอบ (ห้ามมั่ว ใช้ตามนี้เท่านั้น): ' + facts;
    })() },
    ...$json.history
  ]
}) }}

